{
  "name": "express-tailwind-app",
  "version": "0.1.0",
  "private": true,
  "scripts": {
    "build": "tsc -p tsconfig.json",
    "start": "npm run build && node dist/server.js",
    "test": "npm run build && mocha \"tests/**/*.test.js\""
  },
  "dependencies": {
    "express": "^4.19.2"
  },
  "devDependencies": {
    "@types/express": "^4.17.21",
    "@types/node": "^20.11.30",
    "chai": "^4.3.10",
    "mocha": "^10.4.0",
    "supertest": "^6.3.3",
    "typescript": "^5.4.3"
  }
}

import express from 'express';
import path from 'path';

const app = express();

// Serve static assets from the public directory
const publicDir = path.join(__dirname, '..', 'public');
app.use(express.static(publicDir));

// Explicitly serve index.html at root
app.get('/', (_req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

export default app;

import app from './app';

const PORT = Number(process.env.PORT) || 3000;

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

const request = require('supertest');
const { expect } = require('chai');

// Import compiled app from dist
const appModule = require('../dist/app');
const app = appModule.default || appModule;

describe('Express server', () => {
  it('serves index.html at GET /', async () => {
    const res = await request(app).get('/');
    expect(res.status).to.equal(200);
    expect(res.headers['content-type']).to.match(/html/);
    expect(res.text).to.include('Hello World');
  });

  it('serves a static asset at /app.js', async () => {
    const res = await request(app).get('/app.js');
    expect(res.status).to.equal(200);
    expect(res.headers['content-type']).to.match(/javascript|ecmascript/);
    expect(res.text).to.include('App JS loaded');
  });
});
